#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Level;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Entities
{

    [AutoBuffDefinition(VanillaBuffNames.Entity.cursedCandle)]
    public class CursedCandleBuff : BuffDefinition
    {
        public CursedCandleBuff(string nsp, string name) : base(nsp, name)
        {
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, VanillaModelKeys.candleCursed, VanillaModelID.candleCursed);
            AddModifier(new BooleanModifier(LogicEntityProps.REMOVE_ON_DEATH, true));
            AddModifier(new BooleanModifier(LogicEntityProps.NO_DEATH_EFFECTS, true));
            AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostEntityDeathCallback);
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            SetTimer(buff, TimerHelper.NewSecondTimer(DAMAGE_INTERVAL_SECONDS));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var timer = GetTimer(buff);
            if (timer.RunToExpiredAndNotNull())
            {
                var entity = buff.GetEntity();
                if (entity != null)
                {
                    var damageEffects = new DamageEffectList(VanillaDamageEffects.FIRE, VanillaDamageEffects.IGNORE_ARMOR);
                    entity.TakeDamage(GetFireDamage(buff), damageEffects, entity);
                    entity.Spawn(VanillaEffectID.cursedFireburn, entity.GetCenter());
                }
                timer.Reset();
            }
        }
        private void PostEntityDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            float damage = 0;
            float range = 0;
            bool evoked = false;
            foreach (var buff in entity.GetBuffs(this))
            {
                damage += GetExplosionDamage(buff);
                range = Mathf.Max(GetExplosionRange(buff), range);
                evoked = IsEvoked(buff) || evoked;
            }
            if (damage <= 0 || range <= 0)
                return;
            var center = entity.GetCenter();
            if (evoked)
            {
                var damageEffects = new DamageEffectList(VanillaDamageEffects.EXPLOSION, VanillaDamageEffects.DAMAGE_BODY_AFTER_ARMOR_BROKEN, VanillaDamageEffects.MUTE, VanillaDamageEffects.NO_DEATH_EFFECTS, VanillaDamageEffects.REMOVE_ON_DEATH);

                var damageOutputs = entity.ExplodeAgainstFriendly(center, range, entity.GetFaction(), damage, damageEffects);
                damageOutputs.ClearExplosionCorpses();

                Nuke.ExplodeEffects(entity);
            }
            else
            {
                var damageEffects = new DamageEffectList(VanillaDamageEffects.EXPLOSION, VanillaDamageEffects.DAMAGE_BODY_AFTER_ARMOR_BROKEN, VanillaDamageEffects.MUTE);

                entity.ExplodeAgainstFriendly(center, range, entity.GetFaction(), damage, damageEffects);

                Explosion.Spawn(entity, center, range);
                entity.PlaySound(VanillaSoundID.explosion);
                entity.Level.ShakeScreen(10, 0, 15);
            }
            entity.RemoveBuffs(this);
        }
        public static bool IsEvoked(Buff buff) => buff.GetProperty<bool>(PROP_EVOKED);
        public static void SetEvoked(Buff buff, bool value) => buff.SetProperty(PROP_EVOKED, value);
        public static float GetFireDamage(Buff buff) => buff.GetProperty<float>(PROP_FIRE_DAMAGE);
        public static void SetFireDamage(Buff buff, float value) => buff.SetProperty(PROP_FIRE_DAMAGE, value);
        public static float GetExplosionDamage(Buff buff) => buff.GetProperty<float>(PROP_EXPLOSION_DAMAGE);
        public static void SetExplosionDamage(Buff buff, float value) => buff.SetProperty(PROP_EXPLOSION_DAMAGE, value);
        public static float GetExplosionRange(Buff buff) => buff.GetProperty<float>(PROP_EXPLOSION_RANGE);
        public static void SetExplosionRange(Buff buff, float value) => buff.SetProperty(PROP_EXPLOSION_RANGE, value);
        public static FrameTimer? GetTimer(Buff buff) => buff.GetProperty<FrameTimer>(PROP_TIMER);
        public static void SetTimer(Buff buff, FrameTimer? value) => buff.SetProperty(PROP_TIMER, value);
        public const float DAMAGE_INTERVAL_SECONDS = 1f;
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("timer");
        public static readonly VanillaBuffPropertyMeta<bool> PROP_EVOKED = new VanillaBuffPropertyMeta<bool>("evoked");
        public static readonly VanillaBuffPropertyMeta<float> PROP_FIRE_DAMAGE = new VanillaBuffPropertyMeta<float>("fire_damage");
        public static readonly VanillaBuffPropertyMeta<float> PROP_EXPLOSION_DAMAGE = new VanillaBuffPropertyMeta<float>("explosion_damage");
        public static readonly VanillaBuffPropertyMeta<float> PROP_EXPLOSION_RANGE = new VanillaBuffPropertyMeta<float>("explosion_range");
    }
}
